| MCP:HMg9Sb | plugins {
| MCP:HMg9Sb |     id 'java-library'
| MCP:HMg9Sb |     id 'org.springframework.boot' apply(false)
| MCP:HMg9Sb |     id 'io.spring.dependency-management'
| MCP:HMg9Sb |     id 'io.spring.javaformat' apply(false)
| MCP:HMg9Sb |     id 'org.asciidoctor.jvm.convert' apply(false)
| MCP:HMg9Sb | }
| MCP:HMg9Sb | 
| MCP:HMg9Sb | apply from: 'lint.gradle'
| MCP:HMg9Sb | 
| MCP:HMg9Sb | allprojects {
| MCP:HMg9Sb |     group = "${projectGroup}"
| MCP:HMg9Sb |     version = "${applicationVersion}"
| MCP:HMg9Sb | 
| MCP:HMg9Sb |     repositories {
| MCP:HMg9Sb |         mavenCentral()
| MCP:HMg9Sb |     }
| MCP:HMg9Sb | }
| MCP:HMg9Sb | 
| MCP:HMg9Sb | subprojects {
| MCP:HMg9Sb |     apply plugin: 'java-library'
| MCP:HMg9Sb |     apply plugin: 'org.springframework.boot'
| MCP:HMg9Sb |     apply plugin: 'io.spring.dependency-management'
| MCP:HMg9Sb |     apply plugin: 'org.asciidoctor.jvm.convert'
| MCP:HMg9Sb |     
| MCP:HMg9Sb |     dependencyManagement {
| MCP:HMg9Sb |         imports {
| MCP:HMg9Sb |             mavenBom "org.springframework.cloud:spring-cloud-dependencies:${springCloudDependenciesVersion}"
| MCP:HMg9Sb |         }
| MCP:HMg9Sb |     }
| MCP:HMg9Sb | 
| MCP:HMg9Sb |     dependencies {
| MCP:HMg9Sb |         annotationProcessor 'org.springframework.boot:spring-boot-configuration-processor'
| MCP:HMg9Sb |         testImplementation 'org.springframework.boot:spring-boot-test'
| MCP:HMg9Sb |         testImplementation 'org.junit.jupiter:junit-jupiter-api'
| MCP:HMg9Sb |         testImplementation 'org.junit.jupiter:junit-jupiter-engine'
| MCP:HMg9Sb |         testRuntimeOnly 'org.junit.platform:junit-platform-launcher'
| MCP:HMg9Sb |         testImplementation 'org.assertj:assertj-core'
| MCP:HMg9Sb |         testImplementation 'org.mockito:mockito-core'
| MCP:HMg9Sb |     }
| MCP:HMg9Sb | 
| MCP:HMg9Sb |     java {
| MCP:HMg9Sb |         toolchain {
| MCP:HMg9Sb |             languageVersion = JavaLanguageVersion.of(project.javaVersion)
| MCP:HMg9Sb |         }
| MCP:HMg9Sb |     }
| MCP:HMg9Sb | 
| MCP:HMg9Sb |     bootJar.enabled = false
| MCP:HMg9Sb |     jar.enabled = true
| MCP:HMg9Sb | 
| MCP:HMg9Sb |     test {
| MCP:HMg9Sb |         useJUnitPlatform {
| MCP:HMg9Sb |             excludeTags 'develop', 'restdocs'
| MCP:HMg9Sb |         }
| MCP:HMg9Sb |     }
| MCP:HMg9Sb | 
| MCP:HMg9Sb |     testing {
| MCP:HMg9Sb |         suites {
| MCP:HMg9Sb |             test {
| MCP:HMg9Sb |                 targets {
| MCP:HMg9Sb |                     unitTest {
| MCP:HMg9Sb |                         testTask.configure {
| MCP:HMg9Sb |                             group = 'verification'
| MCP:HMg9Sb |                             useJUnitPlatform {
| MCP:HMg9Sb |                                 excludeTags 'develop', 'context', 'restdocs'
| MCP:HMg9Sb |                             }
| MCP:HMg9Sb |                         }
| MCP:HMg9Sb |                     }
| MCP:HMg9Sb | 
| MCP:HMg9Sb |                     contextTest {
| MCP:HMg9Sb |                         testTask.configure {
| MCP:HMg9Sb |                             group = 'verification'
| MCP:HMg9Sb |                             useJUnitPlatform {
| MCP:HMg9Sb |                                 includeTags 'context'
| MCP:HMg9Sb |                             }
| MCP:HMg9Sb |                         }
| MCP:HMg9Sb |                     }
| MCP:HMg9Sb | 
| MCP:HMg9Sb |                     restDocsTest {
| MCP:HMg9Sb |                         testTask.configure {
| MCP:HMg9Sb |                             group = 'verification'
| MCP:HMg9Sb |                             useJUnitPlatform {
| MCP:HMg9Sb |                                 includeTags 'restdocs'
| MCP:HMg9Sb |                             }
| MCP:HMg9Sb |                         }
| MCP:HMg9Sb |                     }
| MCP:HMg9Sb | 
| MCP:HMg9Sb |                     developTest {
| MCP:HMg9Sb |                         testTask.configure {
| MCP:HMg9Sb |                             group = 'verification'
| MCP:HMg9Sb |                             useJUnitPlatform {
| MCP:HMg9Sb |                                 includeTags 'develop'
| MCP:HMg9Sb |                             }
| MCP:HMg9Sb |                         }
| MCP:HMg9Sb |                     }
| MCP:HMg9Sb |                 }
| MCP:HMg9Sb |             }
| MCP:HMg9Sb |         }
| MCP:HMg9Sb |     }
| MCP:HMg9Sb | 
| MCP:HMg9Sb |     tasks.named('asciidoctor').configure {
| MCP:HMg9Sb |         dependsOn restDocsTest
| MCP:HMg9Sb |     }
| MCP:HMg9Sb | }

| MCP:HMg9Sb | subprojects {
| MCP:HMg9Sb |     apply plugin: 'java'
| MCP:HMg9Sb |     apply plugin: 'io.spring.javaformat'
| MCP:HMg9Sb | 
| MCP:HMg9Sb |     dependencies {
| MCP:HMg9Sb |         compileOnly "io.spring.javaformat:spring-javaformat-gradle-plugin:${springJavaFormatVersion}"
| MCP:HMg9Sb |     }
| MCP:HMg9Sb | }
